// src/pages/RegisterManageSub1Page.js
import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import * as XLSX from 'xlsx';

import './RegisterManageSub1Page.css';

function RegisterManageSub1Page() {
  // State cho dữ liệu và các bộ lọc
  const [woods, setWoods] = useState([]);
  const [filter, setFilter] = useState('');
  const [selectedProvince, setSelectedProvince] = useState('');
  const [selectedCommune, setSelectedCommune] = useState('');
  const [selectedNganhNgheKinhDoanhGo, setSelectedNganhNgheKinhDoanhGo] = useState('');
  const [selectedTrangThai, setSelectedTrangThai] = useState('');
  const [selectedLoaiHinhCheBienGo, setSelectedLoaiHinhCheBienGo] = useState('');
  const [selectedNguonGocGo, setSelectedNguonGocGo] = useState('');

  // State cho các dropdown (vẫn lấy từ dữ liệu để dropdown linh hoạt)
  const [uniqueProvinces, setUniqueProvinces] = useState([]);
  // (Các state unique khác có thể được fetch riêng nếu cần)

  // State cho phân trang
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15);

  // State cho việc tải dữ liệu và lỗi
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  // Cấu hình cột (giữ nguyên)
  const initialColumnsConfig = { /* ... giữ nguyên cấu hình cột của bạn ... */ };
  const [columns, setColumns] = useState(initialColumnsConfig);
  const [showColumnOptions, setShowColumnOptions] = useState(false);

  // Hàm fetch dữ liệu được tối ưu hóa
  const fetchWoodBusinesses = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const params = {
        page: currentPage,
        limit: itemsPerPage,
        farmType: 'Đăng ký cơ sở kinh doanh, chế biến gỗ',
        search: filter,
        tinhThanhPho: selectedProvince,
        xaPhuong: selectedCommune,
        trangThai: selectedTrangThai,
        nganhNgheKinhDoanhGo: selectedNganhNgheKinhDoanhGo,
        loaiHinhCheBienGo: selectedLoaiHinhCheBienGo,
        nguonGocGo: selectedNguonGocGo
      };

      // Xóa các params rỗng để không gửi lên server
      Object.keys(params).forEach(key => (params[key] === '' || params[key] === null) && delete params[key]);

      const response = await axios.get('http://localhost:10000/api/farms', {
        headers: { Authorization: `Bearer ${token}` },
        params
      });

      const { docs, totalPages: newTotalPages } = response.data;
      setWoods(docs || []);
      setTotalPages(newTotalPages || 1);

    } catch (err) {
      console.error('Lỗi khi lấy danh sách:', err);
      setError('Không thể tải dữ liệu.');
      setWoods([]);
    } finally {
      setLoading(false);
    }
  }, [
    token, currentPage, itemsPerPage, filter, selectedProvince, 
    selectedCommune, selectedTrangThai, selectedNganhNgheKinhDoanhGo, 
    selectedLoaiHinhCheBienGo, selectedNguonGocGo
  ]);

  // useEffect chính để gọi API khi các dependency thay đổi
  useEffect(() => {
    if (token) {
      fetchWoodBusinesses();
    } else {
      navigate('/');
    }
  }, [fetchWoodBusinesses, navigate, token]);

  // Hàm debounce để tránh gọi API liên tục khi người dùng gõ tìm kiếm
  useEffect(() => {
    const handler = setTimeout(() => {
      setCurrentPage(1); // Reset về trang 1 khi tìm kiếm
      fetchWoodBusinesses();
    }, 500); // Đợi 500ms sau khi người dùng ngừng gõ
    return () => clearTimeout(handler);
  }, [filter]);


  // Các hàm xử lý khác (handleDelete, handleEdit, phân trang, cột...) giữ nguyên
  const handleDelete = async (id) => { /* ... giữ nguyên ... */ };
  const handleEdit = (id) => { /* ... giữ nguyên ... */ };
  const handleNavigateToWoodDetail = (id) => navigate(`/admin/woods/${id}`);
  const paginate = (pageNumber) => setCurrentPage(pageNumber);
  const handleColumnToggle = (key) => { /* ... giữ nguyên ... */ };
  // ... các hàm khác

  return (
    <div className="farm-list-container">
      <h2>📋 Danh sách cơ sở kinh doanh, chế biến gỗ</h2>

      <div className="filter-container">
        <input
          type="text"
          placeholder="🔍 Tìm kiếm..."
          // Không dùng value={filter} trực tiếp để debounce hoạt động
          onChange={e => setFilter(e.target.value)}
        />
        {/* Các dropdown filter khác giữ nguyên */}
      </div>

      {loading ? (
        <p>Đang tải...</p>
      ) : error ? (
        <p className="error-message">{error}</p>
      ) : (
        <>
          {woods.length === 0 ? (
            <p>Không tìm thấy cơ sở nào.</p>
          ) : (
            <table className="table-auto w-full border-collapse">
              {/* thead và tbody hiển thị `woods` thay vì `currentItems` */}
              <tbody>
                {woods.map((item) => (
                  <tr key={item._id}>
                    {/* ... render các cột ... */}
                  </tr>
                ))}
              </tbody>
            </table>
          )}

          <div className="pagination-container">
            <button onClick={() => paginate(currentPage - 1)} disabled={currentPage === 1}>«</button>
            <span>Trang {currentPage} / {totalPages}</span>
            <button onClick={() => paginate(currentPage + 1)} disabled={currentPage === totalPages}>»</button>
          </div>
        </>
      )}
    </div>
  );
}

export default RegisterManageSub1Page;
